export function getBlurDataURL(imageSrc: string): string {
  const filename = imageSrc.split("/").pop();
  if (!filename) return "";
  return placeholders["/images/placeholders/" + filename] ?? "";
}

export function getVideoPoster(videoSrc: string): string {
  const name = videoSrc.split("/").pop()?.replace(/\.mp4$/, ".webp") ?? "";
  return "/images/placeholders/" + name;
}

export function getVideoBlurDataURL(videoSrc: string): string | undefined {
  const name = videoSrc.split("/").pop()?.replace(/\.mp4$/, "-blur.webp");
  if (!name) return undefined;
  return placeholders["/images/placeholders/" + name];
}
